PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE d1_migrations(
		id         INTEGER PRIMARY KEY AUTOINCREMENT,
		name       TEXT UNIQUE,
		applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);
CREATE TABLE roles (
  id        INTEGER PRIMARY KEY AUTOINCREMENT,
  nom       TEXT    NOT NULL UNIQUE,           
  libelle   TEXT    NOT NULL,                  
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE users (
  id            INTEGER PRIMARY KEY AUTOINCREMENT,
  email         TEXT    NOT NULL UNIQUE,
  password_hash TEXT    NOT NULL,
  prenom        TEXT    NOT NULL,
  nom           TEXT    NOT NULL,
  telephone     TEXT,
  role_id       INTEGER NOT NULL DEFAULT 2,    
  boutique_id   INTEGER,                       
  actif         INTEGER NOT NULL DEFAULT 0,    
  email_verifie INTEGER NOT NULL DEFAULT 0,
  created_at    DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at    DATETIME DEFAULT CURRENT_TIMESTAMP, pin_hash TEXT, pin_actif INTEGER NOT NULL DEFAULT 0, google_id TEXT,
  FOREIGN KEY (role_id) REFERENCES roles(id)
);
CREATE TABLE boutiques (
  id           INTEGER PRIMARY KEY AUTOINCREMENT,
  nom          TEXT    NOT NULL,
  siret        TEXT,
  tva_numero   TEXT,
  adresse      TEXT,
  code_postal  TEXT,
  ville        TEXT,
  telephone    TEXT,
  email        TEXT,
  site_web     TEXT,
  logo_url     TEXT,
  actif        INTEGER NOT NULL DEFAULT 1,
  created_at   DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at   DATETIME DEFAULT CURRENT_TIMESTAMP
, slug TEXT, description TEXT, horaires TEXT, facebook_url TEXT, instagram_url TEXT, google_maps_url TEXT);
CREATE TABLE boutique_settings (
  id                  INTEGER PRIMARY KEY AUTOINCREMENT,
  boutique_id         INTEGER NOT NULL UNIQUE,
  
  tva_taux_defaut     REAL    NOT NULL DEFAULT 20.0,  
  monnaie             TEXT    NOT NULL DEFAULT 'EUR',
  devise_symbole      TEXT    NOT NULL DEFAULT '€',
  
  nf525_actif         INTEGER NOT NULL DEFAULT 1,
  
  horaires            TEXT,
  
  notif_email_actif   INTEGER NOT NULL DEFAULT 1,
  notif_sms_actif     INTEGER NOT NULL DEFAULT 0,
  
  paiement_especes    INTEGER NOT NULL DEFAULT 1,
  paiement_cb         INTEGER NOT NULL DEFAULT 1,
  paiement_cheque     INTEGER NOT NULL DEFAULT 1,
  paiement_virement   INTEGER NOT NULL DEFAULT 0,
  updated_at          DATETIME DEFAULT CURRENT_TIMESTAMP, prefix_ticket  TEXT NOT NULL DEFAULT 'TKT', prefix_facture TEXT NOT NULL DEFAULT 'FAC', prefix_devis   TEXT NOT NULL DEFAULT 'DEV', prefix_avoir   TEXT NOT NULL DEFAULT 'AV', prefix_rachat  TEXT NOT NULL DEFAULT 'LP', format_numero  TEXT NOT NULL DEFAULT 'annee', padding_numero INTEGER NOT NULL DEFAULT 5, garantie_defaut_jours INTEGER NOT NULL DEFAULT 90, delai_relance_jours    INTEGER NOT NULL DEFAULT 3, mention_facture        TEXT, pied_de_page           TEXT, email_provider    TEXT NOT NULL DEFAULT 'resend', email_api_key     TEXT, email_from        TEXT, email_notif_ticket_cree    INTEGER NOT NULL DEFAULT 1, email_notif_ticket_termine INTEGER NOT NULL DEFAULT 1, email_notif_sav_ouvert     INTEGER NOT NULL DEFAULT 1, email_notif_relance        INTEGER NOT NULL DEFAULT 1,
  FOREIGN KEY (boutique_id) REFERENCES boutiques(id) ON DELETE CASCADE
);
CREATE TABLE clients (
  id              INTEGER PRIMARY KEY AUTOINCREMENT,
  boutique_id     INTEGER NOT NULL,
  prenom          TEXT    NOT NULL,
  nom             TEXT    NOT NULL,
  email           TEXT,
  telephone       TEXT,
  
  adresse         TEXT,
  code_postal     TEXT,
  ville           TEXT,
  pays            TEXT    NOT NULL DEFAULT 'France',
  
  notes           TEXT,
  actif           INTEGER NOT NULL DEFAULT 1,
  created_at      DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at      DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (boutique_id) REFERENCES boutiques(id)
);
CREATE TABLE appareils (
  id              INTEGER PRIMARY KEY AUTOINCREMENT,
  client_id       INTEGER NOT NULL,
  marque          TEXT    NOT NULL,           
  modele          TEXT    NOT NULL,           
  type            TEXT    NOT NULL DEFAULT 'smartphone',  
  imei            TEXT,                        
  numero_serie    TEXT,
  couleur         TEXT,
  mot_de_passe    TEXT,                        
  notes           TEXT,
  created_at      DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (client_id) REFERENCES clients(id) ON DELETE CASCADE
);
CREATE TABLE tickets (
  id                INTEGER PRIMARY KEY AUTOINCREMENT,
  boutique_id       INTEGER NOT NULL,
  numero            TEXT    NOT NULL UNIQUE,   
  client_id         INTEGER NOT NULL,
  appareil_id       INTEGER,                   
  
  appareil_marque   TEXT    NOT NULL,          
  appareil_modele   TEXT    NOT NULL,
  description_panne TEXT    NOT NULL,
  
  statut            TEXT    NOT NULL DEFAULT 'recu',
  
  technicien_id     INTEGER,                   
  
  diagnostic        TEXT,
  
  prix_estime       REAL,
  prix_final        REAL,
  
  devis_id          INTEGER,
  facture_id        INTEGER,
  
  date_reception    DATETIME DEFAULT CURRENT_TIMESTAMP,
  date_promesse     DATETIME,                  
  date_cloture      DATETIME,                  
  date_livraison    DATETIME,                  
  
  notes_internes    TEXT,
  actif             INTEGER NOT NULL DEFAULT 1,
  created_at        DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at        DATETIME DEFAULT CURRENT_TIMESTAMP, tracking_token TEXT, priorite TEXT NOT NULL DEFAULT 'normale', date_commande_pieces DATETIME, date_reception_pieces DATETIME, archived_at DATETIME, etat_appareil TEXT, code_deverrouillage TEXT, code_sim TEXT, signature_client TEXT, signature_date TEXT,
  FOREIGN KEY (boutique_id)   REFERENCES boutiques(id),
  FOREIGN KEY (client_id)     REFERENCES clients(id),
  FOREIGN KEY (appareil_id)   REFERENCES appareils(id),
  FOREIGN KEY (technicien_id) REFERENCES users(id)
);
CREATE TABLE tickets_statuts_historique (
  id            INTEGER PRIMARY KEY AUTOINCREMENT,
  ticket_id     INTEGER NOT NULL,
  statut_ancien TEXT    NOT NULL,
  statut_nouveau TEXT   NOT NULL,
  user_id       INTEGER NOT NULL,              
  commentaire   TEXT,
  created_at    DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (ticket_id) REFERENCES tickets(id) ON DELETE CASCADE,
  FOREIGN KEY (user_id)   REFERENCES users(id)
);
CREATE TABLE tickets_photos (
  id          INTEGER PRIMARY KEY AUTOINCREMENT,
  ticket_id   INTEGER NOT NULL,
  url_r2      TEXT    NOT NULL,                
  type_photo  TEXT    NOT NULL DEFAULT 'avant', 
  description TEXT,
  created_at  DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (ticket_id) REFERENCES tickets(id) ON DELETE CASCADE
);
CREATE TABLE categories (
  id          INTEGER PRIMARY KEY AUTOINCREMENT,
  boutique_id INTEGER NOT NULL,
  nom         TEXT    NOT NULL,
  parent_id   INTEGER,                         
  actif       INTEGER NOT NULL DEFAULT 1,
  created_at  DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (boutique_id) REFERENCES boutiques(id),
  FOREIGN KEY (parent_id)   REFERENCES categories(id)
);
CREATE TABLE produits (
  id               INTEGER PRIMARY KEY AUTOINCREMENT,
  boutique_id      INTEGER NOT NULL,
  categorie_id     INTEGER,
  sku              TEXT,                        
  nom              TEXT    NOT NULL,
  description      TEXT,
  marque           TEXT,
  
  prix_achat_ht    REAL    NOT NULL DEFAULT 0,
  prix_vente_ht    REAL    NOT NULL DEFAULT 0,
  tva_taux         REAL    NOT NULL DEFAULT 20.0,
  
  stock_actuel     INTEGER NOT NULL DEFAULT 0,
  stock_minimum    INTEGER NOT NULL DEFAULT 5,  
  stock_maximum    INTEGER,
  
  code_barre       TEXT,
  
  fournisseur      TEXT,
  reference_fournisseur TEXT,
  
  actif            INTEGER NOT NULL DEFAULT 1,
  created_at       DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at       DATETIME DEFAULT CURRENT_TIMESTAMP, prix_achat_cump REAL NOT NULL DEFAULT 0, fournisseur_id INTEGER REFERENCES fournisseurs(id), famille TEXT NOT NULL DEFAULT 'piece'
  CHECK (famille IN ('piece', 'accessoire', 'appareil', 'consommable')),
  FOREIGN KEY (boutique_id) REFERENCES boutiques(id),
  FOREIGN KEY (categorie_id) REFERENCES categories(id)
);
CREATE TABLE mouvements_stock (
  id            INTEGER PRIMARY KEY AUTOINCREMENT,
  produit_id    INTEGER NOT NULL,
  boutique_id   INTEGER NOT NULL,
  type_mouvement TEXT   NOT NULL,               
  quantite      INTEGER NOT NULL,               
  stock_avant   INTEGER NOT NULL,               
  stock_apres   INTEGER NOT NULL,               
  
  ticket_id     INTEGER,                        
  user_id       INTEGER NOT NULL,
  motif         TEXT,                           
  created_at    DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (produit_id) REFERENCES produits(id),
  FOREIGN KEY (boutique_id) REFERENCES boutiques(id),
  FOREIGN KEY (ticket_id)  REFERENCES tickets(id),
  FOREIGN KEY (user_id)    REFERENCES users(id)
);
CREATE TABLE devis (
  id            INTEGER PRIMARY KEY AUTOINCREMENT,
  boutique_id   INTEGER NOT NULL,
  numero        TEXT    NOT NULL UNIQUE,        
  client_id     INTEGER NOT NULL,
  ticket_id     INTEGER,                        
  
  total_ht      REAL    NOT NULL DEFAULT 0,
  total_tva     REAL    NOT NULL DEFAULT 0,
  total_ttc     REAL    NOT NULL DEFAULT 0,
  
  statut        TEXT    NOT NULL DEFAULT 'brouillon', 
  
  date_emission  DATETIME DEFAULT CURRENT_TIMESTAMP,
  date_validite  DATETIME,                      
  
  facture_id    INTEGER,                        
  
  notes         TEXT,
  conditions    TEXT,                           
  created_at    DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at    DATETIME DEFAULT CURRENT_TIMESTAMP, public_token TEXT, envoye_le   DATETIME, repondu_le  DATETIME, signature_client TEXT,
  FOREIGN KEY (boutique_id) REFERENCES boutiques(id),
  FOREIGN KEY (client_id)   REFERENCES clients(id),
  FOREIGN KEY (ticket_id)   REFERENCES tickets(id)
);
CREATE TABLE factures (
  id            INTEGER PRIMARY KEY AUTOINCREMENT,
  boutique_id   INTEGER NOT NULL,
  numero        TEXT    NOT NULL UNIQUE,        
  client_id     INTEGER NOT NULL,
  ticket_id     INTEGER,
  devis_id      INTEGER,
  
  total_ht      REAL    NOT NULL DEFAULT 0,
  total_tva     REAL    NOT NULL DEFAULT 0,
  total_ttc     REAL    NOT NULL DEFAULT 0,
  montant_paye  REAL    NOT NULL DEFAULT 0,
  
  statut        TEXT    NOT NULL DEFAULT 'emise', 
  
  date_emission  DATETIME DEFAULT CURRENT_TIMESTAMP,
  date_echeance  DATETIME,
  date_paiement  DATETIME,
  
  hash_nf525    TEXT,                           
  
  notes         TEXT,
  conditions    TEXT,
  created_at    DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at    DATETIME DEFAULT CURRENT_TIMESTAMP, locked       INTEGER NOT NULL DEFAULT 0, issued_at    DATETIME, tracking_token TEXT,
  FOREIGN KEY (boutique_id) REFERENCES boutiques(id),
  FOREIGN KEY (client_id)   REFERENCES clients(id),
  FOREIGN KEY (ticket_id)   REFERENCES tickets(id),
  FOREIGN KEY (devis_id)    REFERENCES devis(id)
);
CREATE TABLE lignes_document (
  id             INTEGER PRIMARY KEY AUTOINCREMENT,
  document_type  TEXT    NOT NULL,              
  document_id    INTEGER NOT NULL,
  ordre          INTEGER NOT NULL DEFAULT 1,    
  description    TEXT    NOT NULL,
  quantite       REAL    NOT NULL DEFAULT 1,
  prix_unitaire_ht REAL  NOT NULL DEFAULT 0,
  tva_taux       REAL    NOT NULL DEFAULT 20.0,
  
  total_ht       REAL    NOT NULL DEFAULT 0,
  total_tva      REAL    NOT NULL DEFAULT 0,
  total_ttc      REAL    NOT NULL DEFAULT 0,
  
  produit_id     INTEGER,
  created_at     DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE paiements (
  id            INTEGER PRIMARY KEY AUTOINCREMENT,
  facture_id    INTEGER NOT NULL,
  boutique_id   INTEGER NOT NULL,
  montant       REAL    NOT NULL,
  mode_paiement TEXT    NOT NULL,               
  reference     TEXT,                           
  date_paiement DATETIME DEFAULT CURRENT_TIMESTAMP,
  user_id       INTEGER NOT NULL,               
  notes         TEXT,
  created_at    DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (facture_id)  REFERENCES factures(id),
  FOREIGN KEY (boutique_id) REFERENCES boutiques(id),
  FOREIGN KEY (user_id)     REFERENCES users(id)
);
CREATE TABLE employes (
  id               INTEGER PRIMARY KEY AUTOINCREMENT,
  boutique_id      INTEGER NOT NULL,
  user_id          INTEGER,                     
  prenom           TEXT    NOT NULL,
  nom              TEXT    NOT NULL,
  email            TEXT,
  telephone        TEXT,
  poste            TEXT    NOT NULL DEFAULT 'technicien', 
  
  taux_horaire     REAL,
  commission_pct   REAL    NOT NULL DEFAULT 0,  
  
  statut_pointage  TEXT    NOT NULL DEFAULT 'absent', 
  
  actif            INTEGER NOT NULL DEFAULT 1,
  date_embauche    TEXT,
  notes            TEXT,
  created_at       DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at       DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (boutique_id) REFERENCES boutiques(id),
  FOREIGN KEY (user_id)     REFERENCES users(id)
);
CREATE TABLE pointages (
  id               INTEGER PRIMARY KEY AUTOINCREMENT,
  employe_id       INTEGER NOT NULL,
  boutique_id      INTEGER NOT NULL,
  
  statut_avant     TEXT    NOT NULL,            
  statut_apres     TEXT    NOT NULL,            
  
  horodatage       DATETIME DEFAULT CURRENT_TIMESTAMP,
  
  latitude         REAL,
  longitude        REAL,
  
  valide_par       INTEGER,                     
  notes            TEXT,
  created_at       DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (employe_id)  REFERENCES employes(id) ON DELETE CASCADE,
  FOREIGN KEY (boutique_id) REFERENCES boutiques(id),
  FOREIGN KEY (valide_par)  REFERENCES users(id)
);
CREATE TABLE commissions (
  id            INTEGER PRIMARY KEY AUTOINCREMENT,
  employe_id    INTEGER NOT NULL,
  ticket_id     INTEGER NOT NULL,
  facture_id    INTEGER,
  montant_base  REAL    NOT NULL,               
  taux_pct      REAL    NOT NULL,               
  montant_commission REAL NOT NULL,             
  statut        TEXT    NOT NULL DEFAULT 'en_attente', 
  date_calcul   DATETIME DEFAULT CURRENT_TIMESTAMP,
  date_paiement DATETIME,
  FOREIGN KEY (employe_id) REFERENCES employes(id),
  FOREIGN KEY (ticket_id)  REFERENCES tickets(id),
  FOREIGN KEY (facture_id) REFERENCES factures(id)
);
CREATE TABLE journal_nf525 (
  id                INTEGER PRIMARY KEY AUTOINCREMENT,
  boutique_id       INTEGER NOT NULL,
  
  type_transaction  TEXT    NOT NULL,           
  reference_id      INTEGER NOT NULL,           
  reference_numero  TEXT    NOT NULL,           
  
  client_id         INTEGER,
  montant_ht        REAL    NOT NULL,
  montant_tva       REAL    NOT NULL,
  montant_ttc       REAL    NOT NULL,
  date_transaction  DATETIME NOT NULL,
  
  hash_precedent    TEXT    NOT NULL DEFAULT '', 
  donnees_hash      TEXT    NOT NULL,           
  hash_courant      TEXT    NOT NULL,           
  
  est_cloture       INTEGER NOT NULL DEFAULT 0, 
  periode_cloture   TEXT,                       
  
  user_id           INTEGER NOT NULL,           
  created_at        DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (boutique_id) REFERENCES boutiques(id),
  FOREIGN KEY (user_id)     REFERENCES users(id)
);
CREATE TABLE clotures_journalieres (
  id              INTEGER PRIMARY KEY AUTOINCREMENT,
  boutique_id     INTEGER NOT NULL,
  date_cloture    TEXT    NOT NULL UNIQUE,       
  
  nb_transactions INTEGER NOT NULL DEFAULT 0,
  total_ht        REAL    NOT NULL DEFAULT 0,
  total_tva       REAL    NOT NULL DEFAULT 0,
  total_ttc       REAL    NOT NULL DEFAULT 0,
  
  hash_cloture    TEXT    NOT NULL,
  hash_precedent  TEXT    NOT NULL DEFAULT '',
  
  user_id         INTEGER NOT NULL,
  created_at      DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (boutique_id) REFERENCES boutiques(id),
  FOREIGN KEY (user_id)     REFERENCES users(id)
);
CREATE TABLE otp_tokens (
  id          INTEGER PRIMARY KEY AUTOINCREMENT,
  email       TEXT    NOT NULL,
  code        TEXT    NOT NULL,                 
  type        TEXT    NOT NULL DEFAULT 'email_verification', 
  expire_at   DATETIME NOT NULL,               
  utilise     INTEGER NOT NULL DEFAULT 0,
  created_at  DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE sequences (
  id           INTEGER PRIMARY KEY AUTOINCREMENT,
  boutique_id  INTEGER NOT NULL,
  type         TEXT    NOT NULL,               
  annee        INTEGER NOT NULL,               
  dernier_num  INTEGER NOT NULL DEFAULT 0,
  UNIQUE(boutique_id, type, annee),
  FOREIGN KEY (boutique_id) REFERENCES boutiques(id)
);
CREATE TABLE audit_logs (
  id           INTEGER PRIMARY KEY AUTOINCREMENT,
  boutique_id  INTEGER,
  user_id      INTEGER,
  action       TEXT    NOT NULL,               
  entite_type  TEXT,                           
  entite_id    INTEGER,
  donnees_avant TEXT,                          
  donnees_apres TEXT,                          
  ip_address   TEXT,
  created_at   DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE avoirs (
  id            INTEGER PRIMARY KEY AUTOINCREMENT,
  boutique_id   INTEGER NOT NULL,
  numero        TEXT    NOT NULL UNIQUE,        
  facture_id    INTEGER NOT NULL,               
  client_id     INTEGER NOT NULL,
  
  type          TEXT    NOT NULL DEFAULT 'remboursement', 
  motif         TEXT    NOT NULL,               
  
  total_ht      REAL    NOT NULL DEFAULT 0,
  total_tva     REAL    NOT NULL DEFAULT 0,
  total_ttc     REAL    NOT NULL DEFAULT 0,
  
  statut        TEXT    NOT NULL DEFAULT 'emis', 
  
  hash_nf525    TEXT,
  
  date_emission DATETIME DEFAULT CURRENT_TIMESTAMP,
  notes         TEXT,
  created_at    DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at    DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (boutique_id) REFERENCES boutiques(id),
  FOREIGN KEY (facture_id)  REFERENCES factures(id),
  FOREIGN KEY (client_id)   REFERENCES clients(id)
);
CREATE TABLE lignes_avoir (
  id               INTEGER PRIMARY KEY AUTOINCREMENT,
  avoir_id         INTEGER NOT NULL,
  ordre            INTEGER NOT NULL DEFAULT 1,
  description      TEXT    NOT NULL,
  quantite         REAL    NOT NULL DEFAULT 1,
  prix_unitaire_ht REAL    NOT NULL DEFAULT 0,
  tva_taux         REAL    NOT NULL DEFAULT 20.0,
  total_ht         REAL    NOT NULL DEFAULT 0,
  total_tva        REAL    NOT NULL DEFAULT 0,
  total_ttc        REAL    NOT NULL DEFAULT 0,
  created_at       DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (avoir_id) REFERENCES avoirs(id)
);
CREATE TABLE rachats (
  id              INTEGER PRIMARY KEY AUTOINCREMENT,
  boutique_id     INTEGER NOT NULL,
  numero          TEXT    NOT NULL UNIQUE,         
  
  vendeur_nom     TEXT    NOT NULL,
  vendeur_prenom  TEXT    NOT NULL,
  vendeur_naissance DATE,                          
  vendeur_adresse TEXT,
  vendeur_cp      TEXT,
  vendeur_ville   TEXT,
  vendeur_piece   TEXT    NOT NULL,                
  vendeur_piece_num TEXT  NOT NULL,                
  vendeur_telephone TEXT,
  
  marque          TEXT    NOT NULL,
  modele          TEXT    NOT NULL,
  imei            TEXT,                            
  imei2           TEXT,                            
  couleur         TEXT,
  capacite        TEXT,                            
  etat            TEXT    NOT NULL DEFAULT 'bon',  
  accessoires     TEXT,                            
  observations    TEXT,                            
  
  prix_rachat     REAL    NOT NULL DEFAULT 0,      
  mode_paiement   TEXT    NOT NULL DEFAULT 'especes', 
  reference_paiement TEXT,                         
  
  statut          TEXT    NOT NULL DEFAULT 'en_stock', 
  
  produit_id      INTEGER,                         
  
  user_id         INTEGER NOT NULL,
  
  hash_nf525      TEXT,
  
  date_rachat     DATETIME DEFAULT CURRENT_TIMESTAMP,
  created_at      DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at      DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (boutique_id) REFERENCES boutiques(id),
  FOREIGN KEY (produit_id)  REFERENCES produits(id),
  FOREIGN KEY (user_id)     REFERENCES users(id)
);
CREATE TABLE permissions (
  id         INTEGER PRIMARY KEY AUTOINCREMENT,
  user_id    INTEGER NOT NULL,
  boutique_id INTEGER NOT NULL,
  action     TEXT    NOT NULL,  
  autorise   INTEGER NOT NULL DEFAULT 1,  
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(user_id, boutique_id, action),
  FOREIGN KEY (user_id)    REFERENCES users(id),
  FOREIGN KEY (boutique_id) REFERENCES boutiques(id)
);
CREATE TABLE categories_services (
  id          INTEGER PRIMARY KEY AUTOINCREMENT,
  boutique_id INTEGER NOT NULL REFERENCES boutiques(id) ON DELETE CASCADE,
  parent_id   INTEGER REFERENCES categories_services(id) ON DELETE SET NULL,
  nom         TEXT    NOT NULL,
  description TEXT,
  couleur     TEXT    DEFAULT '#6366f1',  
  ordre       INTEGER DEFAULT 0,          
  actif       INTEGER NOT NULL DEFAULT 1,
  created_at  DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at  DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE services (
  id              INTEGER PRIMARY KEY AUTOINCREMENT,
  boutique_id     INTEGER NOT NULL REFERENCES boutiques(id) ON DELETE CASCADE,
  categorie_id    INTEGER REFERENCES categories_services(id) ON DELETE SET NULL,
  nom             TEXT    NOT NULL,
  description     TEXT,
  prix_ht         REAL    NOT NULL DEFAULT 0,
  tva_taux        REAL    NOT NULL DEFAULT 20,
  duree_minutes   INTEGER,               
  reference       TEXT,                  
  garantie_jours  INTEGER DEFAULT 0,     
  actif           INTEGER NOT NULL DEFAULT 1,
  created_at      DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at      DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE fournisseurs (
  id            INTEGER PRIMARY KEY AUTOINCREMENT,
  boutique_id   INTEGER NOT NULL,
  nom           TEXT    NOT NULL,
  contact       TEXT,
  email         TEXT,
  telephone     TEXT,
  adresse       TEXT,
  site_web      TEXT,
  notes         TEXT,
  actif         INTEGER NOT NULL DEFAULT 1,
  created_at    DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at    DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (boutique_id) REFERENCES boutiques(id)
);
CREATE TABLE bons_commande (
  id              INTEGER PRIMARY KEY AUTOINCREMENT,
  boutique_id     INTEGER NOT NULL,
  fournisseur_id  INTEGER NOT NULL,
  numero          TEXT    NOT NULL,          
  statut          TEXT    NOT NULL DEFAULT 'draft',
  
  statut_paiement TEXT    NOT NULL DEFAULT 'pending',
  
  date_commande   DATETIME,
  date_livraison_prevue DATETIME,
  date_reception  DATETIME,
  montant_ht      REAL    NOT NULL DEFAULT 0,
  montant_ttc     REAL    NOT NULL DEFAULT 0,
  notes           TEXT,
  ticket_id       INTEGER,                   
  user_id         INTEGER NOT NULL,          
  created_at      DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at      DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (boutique_id)    REFERENCES boutiques(id),
  FOREIGN KEY (fournisseur_id) REFERENCES fournisseurs(id),
  FOREIGN KEY (ticket_id)      REFERENCES tickets(id)
);
CREATE TABLE lignes_bon_commande (
  id              INTEGER PRIMARY KEY AUTOINCREMENT,
  bon_commande_id INTEGER NOT NULL,
  produit_id      INTEGER,                   
  designation     TEXT    NOT NULL,          
  reference       TEXT,
  quantite_commandee  INTEGER NOT NULL DEFAULT 1,
  quantite_recue      INTEGER NOT NULL DEFAULT 0,
  prix_achat_ht   REAL    NOT NULL DEFAULT 0,
  tva_taux        REAL    NOT NULL DEFAULT 20,
  created_at      DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (bon_commande_id) REFERENCES bons_commande(id) ON DELETE CASCADE,
  FOREIGN KEY (produit_id)      REFERENCES produits(id)
);
CREATE TABLE rendez_vous (
  id              INTEGER PRIMARY KEY AUTOINCREMENT,
  boutique_id     INTEGER NOT NULL REFERENCES boutiques(id),
  client_id       INTEGER REFERENCES clients(id),
  ticket_id       INTEGER REFERENCES tickets(id),
  user_id         INTEGER REFERENCES users(id),         
  titre           TEXT    NOT NULL,
  description     TEXT,
  debut           DATETIME NOT NULL,                    
  fin             DATETIME NOT NULL,                    
  duree_minutes   INTEGER NOT NULL DEFAULT 30,
  statut          TEXT    NOT NULL DEFAULT 'PENDING'
                    CHECK(statut IN (
                      'PENDING',        
                      'SCHEDULED',      
                      'DONE',           
                      'NO_SHOW',        
                      'CANCELLED',      
                      'CONVERTED'       
                    )),
  type_rdv        TEXT    NOT NULL DEFAULT 'reparation'
                    CHECK(type_rdv IN (
                      'reparation',     
                      'restitution',    
                      'devis',          
                      'diagnostic',     
                      'autre'
                    )),
  
  nom_client      TEXT,
  telephone_client TEXT,
  
  rappel_envoye   INTEGER NOT NULL DEFAULT 0,
  rappel_minutes  INTEGER NOT NULL DEFAULT 60,          
  
  ical_token      TEXT    UNIQUE,
  
  couleur         TEXT    DEFAULT '#3B82F6',
  
  notes           TEXT,
  actif           INTEGER NOT NULL DEFAULT 1,
  created_at      DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at      DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE boutique_ical_tokens (
  id          INTEGER PRIMARY KEY AUTOINCREMENT,
  boutique_id INTEGER NOT NULL UNIQUE REFERENCES boutiques(id),
  token       TEXT    NOT NULL UNIQUE,
  created_at  DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE sav_dossiers (
  id              INTEGER  PRIMARY KEY AUTOINCREMENT,
  boutique_id     INTEGER  NOT NULL REFERENCES boutiques(id) ON DELETE CASCADE,
  garantie_id     INTEGER  REFERENCES garanties(id) ON DELETE SET NULL,
  ticket_origine_id INTEGER REFERENCES tickets(id) ON DELETE SET NULL,
  ticket_sav_id   INTEGER  REFERENCES tickets(id) ON DELETE SET NULL,  
  client_id       INTEGER  REFERENCES clients(id) ON DELETE SET NULL,
  numero          TEXT     NOT NULL,   
  motif           TEXT     NOT NULL,
  description     TEXT,
  statut          TEXT     NOT NULL DEFAULT 'ouvert'
                  CHECK(statut IN ('ouvert','en_traitement','resolu','refuse','clos')),
  resolution      TEXT,                
  date_ouverture  DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  date_cloture    DATETIME,
  actif           INTEGER  NOT NULL DEFAULT 1,
  created_at      DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at      DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE IF NOT EXISTS "garanties" (
  id              INTEGER  PRIMARY KEY AUTOINCREMENT,
  boutique_id     INTEGER  NOT NULL REFERENCES boutiques(id) ON DELETE CASCADE,
  ticket_id       INTEGER  REFERENCES tickets(id) ON DELETE CASCADE,
  client_id       INTEGER  REFERENCES clients(id) ON DELETE SET NULL,
  appareil_marque TEXT,
  appareil_modele TEXT,
  description_reparation TEXT,
  date_debut      DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  date_fin        DATETIME NOT NULL,
  garantie_jours  INTEGER  NOT NULL DEFAULT 90,
  statut          TEXT     NOT NULL DEFAULT 'active'
                  CHECK(statut IN ('active','expiree','consommee')),
  actif           INTEGER  NOT NULL DEFAULT 1,
  created_at      DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at      DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE email_logs (
  id            INTEGER  PRIMARY KEY AUTOINCREMENT,
  boutique_id   INTEGER  NOT NULL REFERENCES boutiques(id) ON DELETE CASCADE,
  destinataire  TEXT     NOT NULL,
  sujet         TEXT     NOT NULL,
  type          TEXT     NOT NULL  
                CHECK(type IN ('ticket_cree','ticket_termine','sav_ouvert','relance','autre')),
  entite_type   TEXT,              
  entite_id     INTEGER,
  statut        TEXT     NOT NULL DEFAULT 'envoye'
                CHECK(statut IN ('envoye','erreur','simule')),
  erreur        TEXT,              
  provider_id   TEXT,              
  created_at    DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE ordres_reconditionnement (
  id                  INTEGER  PRIMARY KEY AUTOINCREMENT,
  boutique_id         INTEGER  NOT NULL REFERENCES boutiques(id)     ON DELETE CASCADE,
  rachat_id           INTEGER  REFERENCES rachats(id)                ON DELETE SET NULL,
  produit_id          INTEGER  REFERENCES produits(id)               ON DELETE SET NULL,
  
  numero              TEXT     NOT NULL UNIQUE,
  
  statut              TEXT     NOT NULL DEFAULT 'brouillon'
                      CHECK(statut IN ('brouillon','en_cours','termine','abandonne')),
  
  appareil_marque     TEXT,
  appareil_modele     TEXT,
  imei                TEXT,
  couleur             TEXT,
  capacite            TEXT,
  
  prix_rachat         REAL     NOT NULL DEFAULT 0,   
  cout_main_oeuvre    REAL     NOT NULL DEFAULT 0,   
  cout_pieces         REAL     NOT NULL DEFAULT 0,   
  cout_revient        REAL     GENERATED ALWAYS AS (prix_rachat + cout_main_oeuvre + cout_pieces) STORED,
  
  prix_revente_ht     REAL,
  
  description_travaux TEXT,
  
  grade               TEXT     CHECK(grade IN ('A','B','C','D')),
  
  date_debut          DATETIME,
  date_fin            DATETIME,
  actif               INTEGER  NOT NULL DEFAULT 1,
  created_at          DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at          DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE bons_achat (
  id                  INTEGER  PRIMARY KEY AUTOINCREMENT,
  boutique_id         INTEGER  NOT NULL REFERENCES boutiques(id)     ON DELETE CASCADE,
  client_id           INTEGER  REFERENCES clients(id)                ON DELETE SET NULL,
  
  source_type         TEXT     CHECK(source_type IN ('manuel','ticket','facture','sav')),
  source_id           INTEGER, 
  
  code                TEXT     NOT NULL UNIQUE COLLATE NOCASE,
  
  montant             REAL     NOT NULL CHECK(montant > 0),
  montant_utilise     REAL     NOT NULL DEFAULT 0,
  
  statut              TEXT     NOT NULL DEFAULT 'actif'
                      CHECK(statut IN ('actif','utilise','expire','annule')),
  
  date_expiration     DATE,
  
  utilise_le          DATETIME,
  utilise_facture_id  INTEGER  REFERENCES factures(id) ON DELETE SET NULL,
  
  motif               TEXT,
  actif               INTEGER  NOT NULL DEFAULT 1,
  created_at          DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at          DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE kv_store (
  key        TEXT    NOT NULL PRIMARY KEY,
  value      TEXT    NOT NULL,
  expires_at INTEGER          
);
CREATE TABLE boutique_creneaux (
  id           INTEGER PRIMARY KEY AUTOINCREMENT,
  boutique_id  INTEGER NOT NULL REFERENCES boutiques(id),
  jour_semaine INTEGER NOT NULL CHECK (jour_semaine BETWEEN 1 AND 7), 
  heure_debut  TEXT    NOT NULL, 
  heure_fin    TEXT    NOT NULL, 
  duree_slot   INTEGER NOT NULL DEFAULT 30, 
  actif        INTEGER NOT NULL DEFAULT 1
);
CREATE TABLE ticket_photos (
  id          INTEGER  PRIMARY KEY AUTOINCREMENT,
  ticket_id   INTEGER  NOT NULL REFERENCES tickets(id) ON DELETE CASCADE,
  r2_key      TEXT     NOT NULL UNIQUE,
  nom_fichier TEXT     NOT NULL DEFAULT '',
  type_photo  TEXT     NOT NULL DEFAULT 'autre'
                       CHECK (type_photo IN ('avant', 'apres', 'autre')),
  mime_type   TEXT     NOT NULL DEFAULT 'image/jpeg',
  taille      INTEGER  NOT NULL DEFAULT 0,  
  created_at  DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  created_by  INTEGER  REFERENCES users(id)
);
CREATE TABLE service_modeles (
  service_id  INTEGER NOT NULL REFERENCES services(id) ON DELETE CASCADE,
  modele_id   INTEGER NOT NULL REFERENCES "modeles_appareils_old"(id) ON DELETE CASCADE,
  prix_ht_specifique REAL,                   
  actif       INTEGER NOT NULL DEFAULT 1,
  created_at  DATETIME DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (service_id, modele_id)
);
CREATE TABLE marques_appareils (
  id           INTEGER PRIMARY KEY AUTOINCREMENT,
  nom          TEXT    NOT NULL,
  brand_slug   TEXT    UNIQUE,               
  logo_url     TEXT,
  device_count INTEGER DEFAULT 0,            
  source       TEXT    NOT NULL DEFAULT 'manual', 
  ordre        INTEGER DEFAULT 0,
  actif        INTEGER NOT NULL DEFAULT 1,
  synced_at    DATETIME,                     
  created_at   DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at   DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE modeles_appareils (
  id           INTEGER PRIMARY KEY AUTOINCREMENT,
  marque_id    INTEGER NOT NULL REFERENCES marques_appareils(id) ON DELETE CASCADE,
  nom          TEXT    NOT NULL,
  phone_slug   TEXT    UNIQUE,               
  type         TEXT    DEFAULT 'smartphone', 
  annee        INTEGER,
  image_url    TEXT,                         
  source       TEXT    NOT NULL DEFAULT 'manual',
  actif        INTEGER NOT NULL DEFAULT 1,
  created_at   DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at   DATETIME DEFAULT CURRENT_TIMESTAMP,
  UNIQUE (marque_id, nom)
);
CREATE TABLE phone_catalog_sync_log (
  id           INTEGER PRIMARY KEY AUTOINCREMENT,
  brand_slug   TEXT    NOT NULL,
  brand_nom    TEXT,
  status       TEXT    NOT NULL DEFAULT 'pending', 
  modeles_added   INTEGER DEFAULT 0,
  modeles_total   INTEGER DEFAULT 0,
  error_msg    TEXT,
  started_at   DATETIME DEFAULT CURRENT_TIMESTAMP,
  finished_at  DATETIME
);
